      <script data-dynamic dangerouslySetInnerHTML={{ __html: `// ── COUNTDOWN ──────────────────────────────────────
const WEBINAR_DATE = new Date();
WEBINAR_DATE.setDate(WEBINAR_DATE.getDate() + 2);
WEBINAR_DATE.setHours(WEBINAR_DATE.getHours() + 14);
WEBINAR_DATE.setMinutes(WEBINAR_DATE.getMinutes() + 32);
function updateTimer() {
  const dist = WEBINAR_DATE.getTime() - new Date().getTime();
  if (dist < 0) return;
  const d = Math.floor(dist / 86400000);
  const h = Math.floor((dist % 86400000) / 3600000);
  const m = Math.floor((dist % 3600000) / 60000);
  const s = Math.floor((dist % 60000) / 1000);
  document.getElementById('days').textContent    = String(d).padStart(2,'0');
  document.getElementById('hours').textContent   = String(h).padStart(2,'0');
  document.getElementById('minutes').textContent = String(m).padStart(2,'0');
  document.getElementById('seconds').textContent = String(s).padStart(2,'0');
}
updateTimer(); setInterval(updateTimer, 1000);

// ── FORM SUBMIT ────────────────────────────────────
document.getElementById('webinar-form').addEventListener('submit', function(e) {
  e.preventDefault();
  const fname = document.getElementById('fname').value.trim();
  const email = document.getElementById('email').value.trim();
  if (!fname || !email) { alert('Please fill in your name and email to register.'); return; }
  const btn = this.querySelector('.submit-btn');
  btn.textContent = 'Registering...';
  btn.disabled = true;
  setTimeout(() => {
    // TODO: Replace with your GHL webhook:
    // fetch('YOUR_GHL_WEBHOOK_URL', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ firstName: fname, email, phone: document.getElementById('phone').value, stage: document.getElementById('stage').value }) });
    document.getElementById('webinar-form').style.display = 'none';
    document.getElementById('success-msg').style.display = 'block';
    setTimeout(() => { window.location.href = '/thank-you?ref=webinar'; }, 1500);
  }, 1200);
});

// ── SMOOTH SCROLL ──────────────────────────────────
document.querySelectorAll('a[href^="#"]').forEach(a => {
  a.addEventListener('click', function(e) {
    const t = document.querySelector(this.getAttribute('href'));
    if (t) { e.preventDefault(); t.scrollIntoView({ behavior: 'smooth', block: 'start' }); }
  });
});

// ── HIDE STICKY WHEN REG VISIBLE ──────────────────
const reg = document.getElementById('register');
const sticky = document.querySelector('.sticky-cta');
if (reg && sticky) {
  new IntersectionObserver(entries => {
    sticky.style.display = entries[0].isIntersecting ? 'none' : 'block';
  }, { threshold: 0.1 }).observe(reg);
}` }} />
